#include<cstdio>
using namespace std;

int main()
{
	int n,i,c,j,b,a[50][50];
	scanf("%d",&n);
	b=n;
	c=1;
	for(i=1;i<=n;i++)
	{
		for(j=1;j<=n;j++)
		{
			int d=0;
			if(i==j)
			{
				d=1;
				printf("+");
			}
			if((i==c)&&(j==b))
			{
				c++;
				b--;
				if(d==0)
				{
					printf("+");
					d=1;
				}
         	}
			else
			{
				if(d==0)
				{
					printf("-");
				}
			}
		}
		printf("\n");
	}
	return 0;
}
